// Extract cover from Google Books (already fetched — free, no API key)
const gbItem = $input.first().json;
const olItem = $input.last().json;

// Google Books thumbnail (upgrade http to https)
let coverUrl = gbItem?.items?.[0]?.volumeInfo?.imageLinks?.thumbnail || '';
if (coverUrl) {
  coverUrl = coverUrl.replace('http://', 'https://');
}

// Fallback: Open Library cover by ISBN
if (!coverUrl) {
  const isbn = olItem?.docs?.[0]?.isbn?.[0];
  if (isbn) coverUrl = `https://covers.openlibrary.org/b/isbn/${isbn}-L.jpg`;
}

// Final fallback: generic placeholder
if (!coverUrl) {
  coverUrl = 'https://covers.openlibrary.org/b/id/8739161-L.jpg';
}

return [{ json: { coverUrl } }];

